SELECT ?artist WHERE {
  ?originalSong wdt:P31 wd:Q7327;
    wdt:P2580 ?chart;
    wdt:P2048 "1"^^xsd:string;
    wdt:P585 ?date.
  ?chart wdt:P17 wd:Q31.
  FILTER (YEAR(?date) = 1990 && MONTH(?date) = 7).
  ?coverSong wdt:P304 ?originalSong;
    wdt:P175 wd:Q731184.
  ?originalSong wdt:P170 ?artist.
  ?artist wdt:P1004 ?label.
  ?artist p:P1004 ?labelStatement.
  ?labelStatement ps:P1004 ?label.
  ?labelStatement pq:P580 ?startYear.
  FILTER (YEAR(?startYear) = 1987)
}

